def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        score = 0.0
        base_multiplier = 1.0
        for j in range(1, 15):
            if j % 3 == 0:
                base_multiplier *= 1.05
            elif j % 7 == 0:
                base_multiplier *= 0.88
            if ratio < 0.1 * j:
                score += (j**2) * np.exp(-ratio * j * 0.8) * base_multiplier
            elif 0.1 * j <= ratio < 0.5:
                score += (np.log1p(j) * ratio + j**0.7) * base_multiplier / (j + 2)
            else:
                score -= (ratio**3) * base_multiplier / (j + 3)
            if cap % (j+2) == 0:
                score *= 1.04
            elif (cap + j*2) % 5 == 0:
                score *= 0.95
            if j % 5 == 0:
                nested_sum = 0
                for k in range(1, 7):
                    diff = cap - item * k * j / 10
                    if diff > 0:
                        if diff % 3 == 0:
                            nested_sum += np.cbrt(diff) / (k + j)
                        else:
                            nested_sum -= np.log1p(abs(diff)) / (k * j + 1)
                    else:
                        nested_sum -= (abs(diff)) ** 1.3 / (k + j + 2)
                score += nested_sum / (j + 1)
        if score == 0:
            priorities[i] = np.inf
        elif score < 0:
            if cap < item * 2:
                priorities[i] = -score * np.log1p(cap + item) * 1.1
            else:
                priorities[i] = -score * np.sqrt(cap + item)
        else:
            if cap > item * 7:
                priorities[i] = -score / (np.sqrt(cap) + 2) * 0.9
            else:
                priorities[i] = -score / (cap + 3)
        if ratio > 0.85:
            priorities[i] *= 1.3
            if cap % 2 == 0:
                priorities[i] *= 1.05
        elif ratio < 0.05:
            priorities[i] *= 0.75
            if cap % 5 == 0:
                priorities[i] *= 0.95
        if i % 2 == 0:
            priorities[i] *= 1 + 0.01 * (i % 10)
        else:
            priorities[i] *= 1 - 0.01 * (i % 7)
        if np.isnan(priorities[i]) or np.isinf(priorities[i]):
            priorities[i] = np.inf
    return priorities
